Description:
{
  "description": "取得圖書館即將舉辦的活動清單。",
  "required_parameters": [],
  "optional_parameters": [
    {
      "name": "days",
      "type": "NUMBER",
      "description": "往後查詢幾天的活動",
      "default": 30
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "回傳結果上限",
      "default": 20
    }
  ]
}

